import React, { useState, useEffect } from 'react';
import { Route, Routes, useNavigate } from 'react-router-dom';

import Login from './components/pages/Login';
import Generale from './components/pages/Generale';
import Utenti from './components/pages/Utenti';
import Admin from './components/pages/Admin';
import Navbar from './components/UI/navbar/Navbar';

import { AuthContext } from './context';
import ProtectedRoute from './components/ProtectedRoute';

import './App.css';

function App() {
  const [isAuth, setIsAuth] = useState(false);
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    try {
      const storedUser = localStorage.getItem('user');
      if (storedUser) {
        setUser(JSON.parse(storedUser));
        setIsAuth(true);
      }
    } catch {
      setIsAuth(false);
    }
  }, []);

  const logout = () => {
    localStorage.removeItem('user');
    setUser(null);
    setIsAuth(false);
    navigate('/login');
  };

  return (
    <AuthContext.Provider value={{ isAuth, setIsAuth, user, setUser, logout }}>
      {isAuth && <Navbar />}  {/* Навбар показываем только если вошли */}
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route path="/" element={<ProtectedRoute><Generale /></ProtectedRoute>} />
        <Route path="/generale" element={<ProtectedRoute><Generale /></ProtectedRoute>} />
        <Route path="/utenti" element={<ProtectedRoute><Utenti /></ProtectedRoute>} />
        <Route path="/admin" element={<ProtectedRoute role="3"><Admin /></ProtectedRoute>} />
        <Route path="*" element={<ProtectedRoute><Generale /></ProtectedRoute>} />
      </Routes>
    </AuthContext.Provider>
  );
}

export default App;
